    /* ═══  CLEANUP  ═══ */
    (function cleanup(){
        document.querySelectorAll('#ttp,#tth-panel,[id^="tt-"],[id^="tth-"]').forEach(e=>e.remove());
        document.querySelectorAll('.tt-tip,.tth-tip').forEach(e=>e.remove());
        document.querySelectorAll('style[data-tth]').forEach(e=>e.remove());
        document.querySelectorAll('.tt-match,.tth-row').forEach(r=>{r.classList.remove('tt-match','tth-row');r.style.backgroundColor='';r.style.borderLeft='';});
        document.querySelectorAll('.tt-badge,.tth-badge,.tth-page-tag,.tth-injected,.tth-group-tag').forEach(e=>e.remove());
    })();

    /* ═══  ESTILOS  ═══ */
    const sty=document.createElement('style');sty.setAttribute('data-tth','main');
